  3→import cn.hutool.core.util.StrUtil;
  4→import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
  5→import com.baomidou.mybatisplus.core.metadata.IPage;
  6→import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
  7→import com.baomidou.mybatisplus.extension.service.impl.ServiceImpl;
  8→import com.yottastudios.ns.collabspace.shared.util.page.PageHelper;
  9→import com.yottastudios.ns.collabspace.shared.util.page.PageInfo;
 10→import com.yottastudios.ns.collabspace.workspace.entity.NodePermissionLogEntity;
 11→import com.yottastudios.ns.collabspace.workspace.mapper.NodePermissionLogMapper;
 12→import com.yottastudios.ns.collabspace.workspace.service.INodePermissionLogService;
 13→import com.yottastudios.ns.collabspace.workspace.vo.NodePermissionLogVo;
 14→import org.springframework.stereotype.Service;
 15→
 16→import java.util.ArrayList;
 17→import java.util.List;
 18→import java.util.Map;
 19→
 20→import static com.yottastudios.ns.collabspace.control.infrastructure.role.RoleConstants.ROLE_DISPLAY_MAP;
 21→
 22→@Service
 23→public class NodePermissionLogServiceImpl
 24→        extends ServiceImpl<NodePermissionLogMapper, NodePermissionLogEntity>
 25→        implements INodePermissionLogService {
 26→
 27→    @Override
 28→    public PageInfo<NodePermissionLogVo> pageBySpaceNodeId(Long spaceNodeId, String keyword, int pageNo, int pageSize) {
 29→        LambdaQueryWrapper<NodePermissionLogEntity> wrapper = new LambdaQueryWrapper<>();
 30→        wrapper.eq(NodePermissionLogEntity::getSpaceNodeId, spaceNodeId);
 31→        if (StrUtil.isNotBlank(keyword)) {
 32→            // 将中文关键词反向映射为角色码，支持用户用中文搜索角色
 33→            List<String> matchedRoleCodes = new ArrayList<>();
 34→            for (Map.Entry<String, String> entry : ROLE_DISPLAY_MAP.entrySet()) {
 35→                if (entry.getValue().contains(keyword)) {
 36→                    matchedRoleCodes.add(entry.getKey());
 37→                }
 38→            }
 39→            boolean matchRemove = keyword.contains("移除") || "移除所有权限".contains(keyword)
 40→                    || keyword.contains("不可见") || "不可见".contains(keyword);
 41→
 42→            wrapper.and(w -> {
 43→                w.like(NodePermissionLogEntity::getOperatorName, keyword)
 44→                        .or().like(NodePermissionLogEntity::getTargetName, keyword);
 45→                if (!matchedRoleCodes.isEmpty()) {
 46→                    w.or().in(NodePermissionLogEntity::getNewRole, matchedRoleCodes)
 47→                            .or().in(NodePermissionLogEntity::getOldRole, matchedRoleCodes);
 48→                }
 49→                if (matchRemove) {
 50→                    w.or().eq(NodePermissionLogEntity::getAction, "remove");
 51→                }
 52→            });
 53→        }
 54→        wrapper.orderByDesc(NodePermissionLogEntity::getCreatedAt);
 55→
 56→        IPage<NodePermissionLogEntity> page = page(new Page<>(pageNo, pageSize), wrapper);
 57→        IPage<NodePermissionLogVo> voPage = page.convert(this::toVo);
 58→        return PageHelper.build(voPage);
 59→    }
 60→
 61→    @Override
 62→    public void log(Long spaceNodeId, String spaceId, Long operatorId, String operatorName,
 63→                    String targetName, Integer targetType, String action, String oldRole, String newRole) {
 64→        NodePermissionLogEntity entity = NodePermissionLogEntity.builder()
 65→                .spaceNodeId(spaceNodeId)
 66→                .spaceId(spaceId)
 67→                .operatorId(operatorId)
 68→                .operatorName(operatorName)
 69→                .targetName(targetName)
 70→                .targetType(targetType)
 71→                .action(action)
 72→                .oldRole(oldRole)
 73→                .newRole(newRole)
 74→                .build();
 75→        save(entity);
 76→    }
