package com.yottastudios.ns.collabspace.base.service.impl;

import com.baomidou.mybatisplus.core.conditions.query.QueryWrapper;
import com.baomidou.mybatisplus.core.conditions.update.UpdateWrapper;
import com.baomidou.mybatisplus.extension.service.impl.ServiceImpl;
import com.yottastudios.ns.collabspace.base.entity.NodeEntity;
import com.yottastudios.ns.collabspace.base.mapper.NodeMapper;
import com.yottastudios.ns.collabspace.base.service.INodeService;
import org.apache.commons.collections4.CollectionUtils;
import org.springframework.stereotype.Service;

import java.util.List;

import static com.yottastudios.ns.collabspace.core.support.tree.v2.DefaultTreeBuildFactory.ROOT_PARENT_ID;

@Service
public class NodeServiceImpl extends ServiceImpl<NodeMapper, NodeEntity> implements INodeService {

    @Override
    public List<NodeEntity> getByTreeIdAndParentIdAndNodeKey(String treeId, Long parentId, Integer nodeKey) {
        QueryWrapper<NodeEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda()
                .eq(NodeEntity::getTreeId, treeId)
                .eq(NodeEntity::getNodeKey, nodeKey)
                .eq(NodeEntity::getParentId, parentId);
        return list(queryWrapper);
    }

    @Override
    public NodeEntity getNodeByPreId(String treeId, Integer nodeKey, Long parentId, Long preId) {
        QueryWrapper<NodeEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda()
                .eq(NodeEntity::getTreeId, treeId)
                .eq(NodeEntity::getNodeKey, nodeKey)
                .eq(NodeEntity::getParentId, parentId)
                .eq(NodeEntity::getPreId, preId)
                .getSqlFirst();
        return getOne(queryWrapper);
    }

    @Override
    public void updatePreId(Long preId, Long id) {
        UpdateWrapper<NodeEntity> updateWrapper = new UpdateWrapper<>();
        updateWrapper.lambda()
                .set(NodeEntity::getPreId, preId)
                .eq(NodeEntity::getId, id);
        update(updateWrapper);
    }

    @Override
    public NodeEntity getByRelId(Long relId) {
        QueryWrapper<NodeEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda()
                .eq(NodeEntity::getRelId, relId)
                .getSqlFirst();
        return getOne(queryWrapper);
    }

    @Override
    public List<NodeEntity> listByRelIds(List<Long> ids) {
        if (CollectionUtils.isEmpty(ids)) {
            return List.of();
        }
        QueryWrapper<NodeEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda()
                .in(NodeEntity::getRelId, ids);
        return list(queryWrapper);
    }

    @Override
    public NodeEntity getFirstChildNodeByParentId(Long parentId, String treeId, Integer nodeKey) {
        QueryWrapper<NodeEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda()
                .eq(NodeEntity::getTreeId, treeId)
                .eq(NodeEntity::getNodeKey, nodeKey)
                .eq(NodeEntity::getParentId, parentId)
                .eq(NodeEntity::getPreId, ROOT_PARENT_ID)
                .getSqlFirst();
        return getOne(queryWrapper);
    }

    @Override
    public void recoverNodeByRelId(Long relId){
        baseMapper.recoverNodeByRelId(relId);
    }

    @Override
    public NodeEntity getByRelIdAllStatus(Long relId){
        return  baseMapper.getByRelIdAllStatus(relId);
    }

    @Override
    public List<NodeEntity> listSubtreeByRelId(Long relId) {
        return baseMapper.listSubtreeByRelId(relId);
    }

    @Override
    public List<NodeEntity> listAncestorsByRelId(Long relId) {
        return baseMapper.listAncestorsByRelId(relId);
    }
}

