package com.yottastudios.ns.collabspace.workspace.service.impl;

import com.baomidou.mybatisplus.core.conditions.query.QueryWrapper;
import com.baomidou.mybatisplus.extension.service.impl.ServiceImpl;
import com.yottastudios.ns.collabspace.workspace.entity.ShareScopeEntity;
import com.yottastudios.ns.collabspace.workspace.mapper.ShareScopeMapper;
import com.yottastudios.ns.collabspace.workspace.service.IShareScopeService;
import org.springframework.stereotype.Service;
import java.util.List;

@Service
public class ShareScopeServiceImpl extends ServiceImpl<ShareScopeMapper, ShareScopeEntity> implements IShareScopeService {

    @Override
    public ShareScopeEntity getByShareId(String shareId) {
        QueryWrapper<ShareScopeEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().eq(ShareScopeEntity::getShareId, shareId);
        return getOne(queryWrapper);
    }

    @Override
    public List<ShareScopeEntity> listByShareIds(List<String> shareIds) {
        if (shareIds == null || shareIds.isEmpty()) {
            return List.of();
        }
        QueryWrapper<ShareScopeEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().in(ShareScopeEntity::getShareId, shareIds);
        return list(queryWrapper);
    }
}

