  1→package com.yottastudios.ns.collabspace.control.service.impl;
  2→
  3→import com.baomidou.mybatisplus.core.conditions.query.QueryWrapper;
  4→import com.baomidou.mybatisplus.core.toolkit.IdWorker;
  5→import com.baomidou.mybatisplus.extension.service.impl.ServiceImpl;
  6→import com.yottastudios.ns.collabspace.control.entity.ControlRoleEntity;
  7→import com.yottastudios.ns.collabspace.control.mapper.ControlRoleMapper;
  8→import com.yottastudios.ns.collabspace.control.service.IControlRoleService;
  9→import org.apache.commons.collections4.CollectionUtils;
 10→import org.springframework.stereotype.Service;
 11→import org.springframework.transaction.annotation.Transactional;
 12→
 13→import java.io.Serializable;
 14→import java.util.*;
 15→
 16→@Service
 17→public class ControlRoleServiceImpl extends ServiceImpl<ControlRoleMapper, ControlRoleEntity> implements IControlRoleService {
 18→    @Override
 19→    public List<ControlRoleEntity> getByControlId(String controlId) {
 20→        QueryWrapper<ControlRoleEntity> queryWrapper = new QueryWrapper<>();
 21→        queryWrapper.lambda().eq(ControlRoleEntity::getControlId, controlId);
 22→        return list(queryWrapper);
 23→    }
 24→
 25→    @Override
 26→    public List<ControlRoleEntity> getByControlIds(Collection<? extends Serializable> controlIds) {
 27→        if (CollectionUtils.isEmpty(controlIds)) {
 28→            return new ArrayList<>();
 29→        }
 30→        QueryWrapper<ControlRoleEntity> queryWrapper = new QueryWrapper<>();
 31→        queryWrapper.lambda().in(ControlRoleEntity::getControlId, controlIds);
 32→        return list(queryWrapper);
 33→    }
 34→
 35→    @Override
 36→    @Transactional
 37→    public void saveOrUpdateControlRole(Long userId, String controlId, List<Long> unitIds, String role) {
 38→        Set<Long> insertUnitIds = new HashSet<>(unitIds);
 39→        List<ControlRoleEntity> controlRoles = getByControlId(controlId);
 40→        // exist -> update
 41→        controlRoles.forEach(controlRole -> {
 42→            Long unitId = controlRole.getUnitId();
 43→            if (insertUnitIds.contains(unitId)) {
 44→                controlRole.setRoleCode(role);
 45→                insertUnitIds.remove(unitId);
 46→            }
 47→        });
 48→        // not exist -> insert
 49→        insertUnitIds.forEach(unitId -> {
 50→            ControlRoleEntity controlRoleEntity = ControlRoleEntity.builder()
 51→                    .id(IdWorker.getId())
 52→                    .controlId(controlId)
 53→                    .unitId(unitId)
 54→                    .roleCode(role)
 55→                    .createdBy(userId)
 56→                    .updatedBy(userId)
 57→                    .build();
 58→            controlRoles.add(controlRoleEntity);
 59→        });
 60→
 61→        if (CollectionUtils.isNotEmpty(controlRoles)) {
 62→            saveOrUpdateBatch(controlRoles);
 63→        }
 64→    }
 65→
 66→    @Override
 67→    @Transactional
 68→    public void removeByControlIdAndUnitIds(String controlId, List<Long> unitIds) {
 69→        List<ControlRoleEntity> entities = getByControlIdAndUnitIds(controlId, unitIds);
 70→        removeByIds(entities);
 71→    }
 72→
 73→    @Override
 74→    public List<ControlRoleEntity> getByControlIdAndUnitIds(String controlId, List<Long> unitIds) {
 75→        if (CollectionUtils.isEmpty(unitIds)) {
 76→            return new ArrayList<>();
 77→        }
 78→        QueryWrapper<ControlRoleEntity> queryWrapper = new QueryWrapper<>();
 79→        queryWrapper.lambda().eq(ControlRoleEntity::getControlId, controlId)
 80→                .in(ControlRoleEntity::getUnitId, unitIds);
 81→        return list(queryWrapper);
 82→    }
 83→
 84→    @Override
 85→    @Transactional
 86→    public void removeControl(List<String> controlIds) {
 87→        if (CollectionUtils.isEmpty(controlIds)) {
 88→            return;
 89→        }
 90→        QueryWrapper<ControlRoleEntity> queryWrapper = new QueryWrapper<>();
 91→        queryWrapper.lambda().in(ControlRoleEntity::getControlId, controlIds);
 92→        remove(queryWrapper);
 93→    }
 94→
 95→    @Override
 96→    public List<String> getControlIdsByUnitId(Long unitId) {
 97→        if (unitId == null) {
 98→            return new ArrayList<>();
 99→        }
100→        QueryWrapper<ControlRoleEntity> queryWrapper = new QueryWrapper<>();
101→        queryWrapper.lambda()
102→                .eq(ControlRoleEntity::getUnitId, unitId)
103→                .select(ControlRoleEntity::getControlId);
104→        return list(queryWrapper).stream()
105→                .map(ControlRoleEntity::getControlId)
106→                .distinct()
107→                .toList();
108→    }
109→}
