import com.baomidou.mybatisplus.core.conditions.query.QueryWrapper;
import com.baomidou.mybatisplus.core.toolkit.IdWorker;
import com.baomidou.mybatisplus.extension.service.impl.ServiceImpl;
import com.yottastudios.ns.collabspace.control.entity.ControlRoleEntity;
import com.yottastudios.ns.collabspace.control.mapper.ControlRoleMapper;
import com.yottastudios.ns.collabspace.control.service.IControlRoleService;
import org.apache.commons.collections4.CollectionUtils;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.io.Serializable;
import java.util.*;

@Service
public class ControlRoleServiceImpl extends ServiceImpl<ControlRoleMapper, ControlRoleEntity> implements IControlRoleService {
    @Override
    public List<ControlRoleEntity> getByControlId(String controlId) {
        QueryWrapper<ControlRoleEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().eq(ControlRoleEntity::getControlId, controlId);
        return list(queryWrapper);
    }

    @Override
    public List<ControlRoleEntity> getByControlIds(Collection<? extends Serializable> controlIds) {
        if (CollectionUtils.isEmpty(controlIds)) {
            return new ArrayList<>();
        }
        QueryWrapper<ControlRoleEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().in(ControlRoleEntity::getControlId, controlIds);
        return list(queryWrapper);
    }

    @Override
    @Transactional
    public void saveOrUpdateControlRole(Long userId, String controlId, List<Long> unitIds, String role) {
        Set<Long> insertUnitIds = new HashSet<>(unitIds);
        List<ControlRoleEntity> controlRoles = getByControlId(controlId);
        // exist -> update
        controlRoles.forEach(controlRole -> {
            Long unitId = controlRole.getUnitId();
            if (insertUnitIds.contains(unitId)) {
                controlRole.setRoleCode(role);
                insertUnitIds.remove(unitId);
            }
        });
        // not exist -> insert
        insertUnitIds.forEach(unitId -> {
            ControlRoleEntity controlRoleEntity = ControlRoleEntity.builder()
                    .id(IdWorker.getId())
                    .controlId(controlId)
                    .unitId(unitId)
                    .roleCode(role)
                    .createdBy(userId)
                    .updatedBy(userId)
                    .build();
            controlRoles.add(controlRoleEntity);
        });

        if (CollectionUtils.isNotEmpty(controlRoles)) {
            saveOrUpdateBatch(controlRoles);
        }
    }

    @Override
    @Transactional
    public void removeByControlIdAndUnitIds(String controlId, List<Long> unitIds) {
        List<ControlRoleEntity> entities = getByControlIdAndUnitIds(controlId, unitIds);
        removeByIds(entities);
    }

    @Override
    public List<ControlRoleEntity> getByControlIdAndUnitIds(String controlId, List<Long> unitIds) {
        if (CollectionUtils.isEmpty(unitIds)) {
            return new ArrayList<>();
        }
        QueryWrapper<ControlRoleEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().eq(ControlRoleEntity::getControlId, controlId)
                .in(ControlRoleEntity::getUnitId, unitIds);
        return list(queryWrapper);
    }

    @Override
    @Transactional
    public void removeControl(List<String> controlIds) {
        if (CollectionUtils.isEmpty(controlIds)) {
            return;
        }
        QueryWrapper<ControlRoleEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().in(ControlRoleEntity::getControlId, controlIds);
        remove(queryWrapper);
    }

    @Override
    public List<String> getControlIdsByUnitId(Long unitId) {
        if (unitId == null) {
            return new ArrayList<>();
        }
        QueryWrapper<ControlRoleEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda()
                .eq(ControlRoleEntity::getUnitId, unitId)
                .select(ControlRoleEntity::getControlId);
        return list(queryWrapper).stream()
                .map(ControlRoleEntity::getControlId)
                .distinct()
                .toList();
    }
}

