package com.yottastudios.ns.collabspace.control.service.impl;

import com.baomidou.mybatisplus.core.conditions.query.QueryWrapper;
import com.baomidou.mybatisplus.core.toolkit.IdWorker;
import com.baomidou.mybatisplus.extension.service.impl.ServiceImpl;
import com.yottastudios.ns.collabspace.control.entity.ControlEntity;
import com.yottastudios.ns.collabspace.control.infrastructure.ControlType;
import com.yottastudios.ns.collabspace.control.mapper.ControlMapper;
import com.yottastudios.ns.collabspace.control.service.IControlService;
import org.apache.commons.collections4.CollectionUtils;
import org.springframework.stereotype.Service;

import java.util.ArrayList;
import java.util.List;

@Service
public class ControlServiceImpl extends ServiceImpl<ControlMapper, ControlEntity> implements IControlService {

    @Override
    public ControlEntity getByControlId(String controlId) {
        QueryWrapper<ControlEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().eq(ControlEntity::getControlId, controlId);
        return getOne(queryWrapper);
    }

    @Override
    public List<ControlEntity> getByControlIds(List<String> controlIds) {
        if (CollectionUtils.isEmpty(controlIds)) {
            return new ArrayList<>();
        }
        QueryWrapper<ControlEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().in(ControlEntity::getControlId, controlIds);
        return list(queryWrapper);
    }

    @Override
    public boolean existsByControlId(String controlId) {
        QueryWrapper<ControlEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().eq(ControlEntity::getControlId, controlId);
        return count(queryWrapper) > 0;
    }

    @Override
    public void create(Long userId, String spaceId, String controlId, ControlType controlType) {
        ControlEntity entity = ControlEntity.builder()
                .id(IdWorker.getId())
                .spaceId(spaceId)
                .controlId(controlId)
                .controlType(controlType.getVal())
                .createdBy(userId)
                .updatedBy(userId)
                .build();
        save(entity);
    }

    @Override
    public void removeControl(List<String> controlIds) {
        if (CollectionUtils.isEmpty(controlIds)) {
            return;
        }
        QueryWrapper<ControlEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().in(ControlEntity::getControlId, controlIds);
        remove(queryWrapper);
    }
}

