package com.yottastudios.ns.collabspace.space.service.impl;

import com.baomidou.mybatisplus.core.conditions.query.QueryWrapper;
import com.baomidou.mybatisplus.core.metadata.IPage;
import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
import com.baomidou.mybatisplus.extension.service.impl.ServiceImpl;
import com.yottastudios.ns.collabspace.core.util.ExceptionUtil;
import com.yottastudios.ns.collabspace.space.entity.SpaceEntity;
import com.yottastudios.ns.collabspace.space.enums.SpaceException;
import com.yottastudios.ns.collabspace.space.mapper.SpaceMapper;
import com.yottastudios.ns.collabspace.space.service.ISpaceService;
import com.yottastudios.ns.collabspace.space.vo.SuperSpaceVo;
import org.springframework.stereotype.Service;

import java.util.List;

@Service
public class SpaceServiceImpl extends ServiceImpl<SpaceMapper, SpaceEntity> implements ISpaceService {
    @Override
    public SpaceEntity add(String spaceId, String name, Long userId) {
        SpaceEntity entity = SpaceEntity.builder()
                .spaceId(spaceId)
                .name(name)
                .owner(userId)
                .build();
        save(entity);
        return entity;
    }

    @Override
    public List<SpaceEntity> listByIds(List<String> spaceIds, boolean containForbidden) {
        QueryWrapper<SpaceEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().in(SpaceEntity::getSpaceId, spaceIds);
        if  (!containForbidden) {
            queryWrapper.lambda().ne(SpaceEntity::getIsForbid, true);
        }
        return list(queryWrapper);
    }

    @Override
    public SpaceEntity getBySpaceId(String spaceId) {
        QueryWrapper<SpaceEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().eq(SpaceEntity::getSpaceId, spaceId).
                eq(SpaceEntity::getIsForbid, false);
        return getOne(queryWrapper);
    }

    @Override
    public SpaceEntity getBySpaceId(String spaceId, boolean containForbidden) {
        QueryWrapper<SpaceEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().eq(SpaceEntity::getSpaceId, spaceId);
        if (!containForbidden) {
            queryWrapper.lambda().eq(SpaceEntity::getIsForbid, false);
        }
        return getOne(queryWrapper);
    }

    @Override
    public List<SpaceEntity> listByName(String name) {
        QueryWrapper<SpaceEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().like(SpaceEntity::getName, name);
        return list(queryWrapper);
    }

    @Override
    public List<SpaceEntity> matchByName(String name) {
        QueryWrapper<SpaceEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().eq(SpaceEntity::getName, name);
        return list(queryWrapper);
    }

    @Override
    public List<SpaceEntity> getOwnSpaces(Long userId) {
        QueryWrapper<SpaceEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().eq(SpaceEntity::getOwner, userId).
                eq(SpaceEntity::getIsForbid, false);
        return list(queryWrapper);
    }

    @Override
    public void checkSpaceExist(String spaceId) {
        QueryWrapper<SpaceEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().eq(SpaceEntity::getSpaceId, spaceId);
        boolean exists = this.exists(queryWrapper);
        ExceptionUtil.isTrue(exists, SpaceException.NOT_EXIST);
    }

    @Override
    public IPage<SuperSpaceVo> getSpaceList(Page<SuperSpaceVo> page) {

        // 创建 SpaceEntity 类型的分页对象
        Page<SpaceEntity> pageSpace = new Page<>(page.getCurrent(), page.getSize());

        // 构建查询条件
        QueryWrapper<SpaceEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda()
                .eq(SpaceEntity::getIsDeleted, false)
                .orderByDesc(SpaceEntity::getCreatedAt);

        // 分页查询空间实体
        IPage<SpaceEntity> spaceEntityPage = page(pageSpace, queryWrapper);

        // 使用convert方法转换，会自动保留分页信息
        return spaceEntityPage.convert(spaceEntity -> {
            SuperSpaceVo vo = new SuperSpaceVo();
            vo.setSpaceName(spaceEntity.getName());
            vo.setSpaceId(spaceEntity.getSpaceId());
            vo.setIsForbid(spaceEntity.getIsForbid());
            return vo;
        });
    }

}

